#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* A = (int*) malloc((N - 1) * sizeof(int));
        for (int i = 0; i < N - 1; i++) {
            scanf("%d", &A[i]);
        }
        int* B = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        double min_integral = 1e18;
        for (int mask = 0; mask < (1 << N); mask++) {
            double integral = 0.0;
            double g_t = B[0];
            for (int i = 0; i < N - 1; i++) {
                if ((mask & (1 << i)) != 0) {
                    g_t += K * (A[i] - (i > 0 ? A[i - 1] : 0));
                }
                integral += fabs(g_t - B[i + 1]) * (i < N - 2 ? A[i + 1] - A[i] : 1e18);
            }
            min_integral = fmin(min_integral, integral);
        }
        printf("%.6f\n", min_integral);
        free(A);
        free(B);
    }
    return 0;
}

