import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[] A = new int[N - 1];
            for (int i = 0; i < N - 1; i++) {
                A[i] = scanner.nextInt();
            }
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                B[i] = scanner.nextInt();
            }
            double min_integral = 1e18;
            for (int mask = 0; mask < (1 << N); mask++) {
                double integral = 0.0;
                double g_t = B[0];
                for (int i = 0; i < N - 1; i++) {
                    if ((mask & (1 << i)) != 0) {
                        g_t += K * (A[i] - (i > 0 ? A[i - 1] : 0));
                    }
                    integral += Math.abs(g_t - B[i + 1]) * (i < N - 2 ? A[i + 1] - A[i] : 1e18);
                }
                min_integral = Math.min(min_integral, integral);
            }
            System.out.printf("%.6f\n", min_integral);
        }
    }
}

